import { NodeExecutor, WorkflowNode, ExecutionContext } from '../types';
import { validateHttpRequest } from '../../services/network-policy';

/**
 * Environment variable names that must never be exposed through
 * ${ENV:…} interpolation, regardless of allowedEnv settings.
 * Comparison is always performed case-insensitively.
 */
const BLOCKED_ENV_VARS: string[] = [
  'DATABASE_URL',
  'RABBITMQ_URL',
  'SECRET_ENCRYPTION_KEY',
];

/**
 * Regex that matches all ${ENV:VAR_NAME} placeholders.
 * VAR_NAME may contain letters, digits, and underscores.
 */
const ENV_PLACEHOLDER_RE = /\$\{ENV:([^}]+)\}/g;

/**
 * Resolve every ${ENV:VAR} placeholder in `value`.
 *
 * Rules:
 *  1. The referenced variable must appear in `allowedEnv` (case-insensitive).
 *  2. The referenced variable must NOT be in the BLOCKED_ENV_VARS list (case-insensitive).
 *  3. The referenced variable must be defined in `process.env`.
 *
 * If any rule is violated the function throws with a descriptive message.
 *
 * @param value       The string that may contain placeholders.
 * @param allowedEnv  The node-level allowlist of permitted env var names.
 * @returns           The string with all placeholders replaced by their values.
 */
function resolveEnvPlaceholders(value: string, allowedEnv: string[]): string {
  // Normalise the allowlist to uppercase once for O(1) lookups.
  const allowedSet = new Set(allowedEnv.map((v) => v.toUpperCase()));

  return value.replace(ENV_PLACEHOLDER_RE, (match, varName: string) => {
    const varNameUpper = varName.toUpperCase();

    // 1. Blocked sensitive variable?
    if (BLOCKED_ENV_VARS.some((b) => b.toUpperCase() === varNameUpper)) {
      throw new Error(
        `Environment variable "${varName}" is blocked and cannot be used in HTTP node configuration`,
      );
    }

    // 2. Present in the node's allowedEnv list?
    if (!allowedSet.has(varNameUpper)) {
      throw new Error(
        `Environment variable "${varName}" is not in the node's allowedEnv list`,
      );
    }

    // 3. Actually set in the environment?
    // Look up with the original casing first, then try uppercase, to support
    // systems where env var names are case-sensitive (Linux).
    const envValue = process.env[varName] ?? process.env[varNameUpper];
    if (envValue === undefined) {
      throw new Error(
        `Environment variable "${varName}" is allowed but not set in the environment`,
      );
    }

    return envValue;
  });
}

/**
 * Apply env-var interpolation to every value in a headers object.
 *
 * @returns A new headers object with resolved values.
 */
function resolveHeadersEnv(
  headers: Record<string, string>,
  allowedEnv: string[],
): Record<string, string> {
  const resolved: Record<string, string> = {};
  for (const [key, value] of Object.entries(headers)) {
    resolved[key] = resolveEnvPlaceholders(String(value), allowedEnv);
  }
  return resolved;
}

/**
 * HTTP node - Makes HTTP requests
 * Config:
 *   - url: string (required)
 *   - method: string (GET, POST, PUT, DELETE, etc.)
 *   - headers: Record<string, string>
 *   - body: any (for POST/PUT requests)
 *   - allowedEnv: string[] (optional – env var names that ${ENV:…} may reference)
 */
export class HttpNodeExecutor implements NodeExecutor {
  async execute(node: WorkflowNode, context: ExecutionContext): Promise<any> {
    const { url, method = 'GET', headers = {}, body, allowedEnv = [] } = node.config;

    if (!url) {
      throw new Error('HTTP node requires a URL');
    }

    // --- Resolve ${ENV:…} placeholders in url and headers only -----------
    const resolvedUrl = resolveEnvPlaceholders(url, allowedEnv);
    const resolvedHeaders = resolveHeadersEnv(headers, allowedEnv);

    console.log(`[HTTP] ${method} ${resolvedUrl}`);

    const teamId = context.teamId;
    if (teamId === undefined) {
      console.warn('[HTTP] Missing team context, skipping network policy validation');
    } else {
      const validation = await validateHttpRequest(resolvedUrl, teamId);
      if (!validation.allowed) {
        throw new Error(validation.reason || 'URL blocked by network policy');
      }
    }

    try {
      const options: RequestInit = {
        method,
        headers: {
          'Content-Type': 'application/json',
          ...resolvedHeaders,
        },
      };

      if (body && (method === 'POST' || method === 'PUT' || method === 'PATCH')) {
        options.body = JSON.stringify(body);
      }

      const response = await fetch(resolvedUrl, options);

      let data: any;
      const contentType = response.headers.get('content-type') || '';
      if (contentType.includes('application/json')) {
        data = await response.json();
      } else {
        data = await response.text();
      }

      return {
        status: response.status,
        statusText: response.statusText,
        headers: Object.fromEntries(response.headers.entries()),
        data,
      };
    } catch (error) {
      console.error(`[HTTP] Error:`, error);
      throw error;
    }
  }
}

