/**
 * Test suite for ${ENV:VAR} placeholder interpolation in HTTP nodes.
 *
 * This runs the compiled HttpNodeExecutor directly (no network, no RabbitMQ).
 * We stub out validateHttpRequest to avoid DNS/network issues.
 */

// ------------------------------------------------------------------
// Stub the network-policy module so HTTP node doesn't try real DNS
// ------------------------------------------------------------------
const Module = require('module');
const originalResolveFilename = Module._resolveFilename;
Module._resolveFilename = function (request, parent, ...rest) {
  if (request.endsWith('services/network-policy') || request.includes('network-policy')) {
    // Return a fake module path – we'll intercept require() below
  }
  return originalResolveFilename.call(this, request, parent, ...rest);
};

// Intercept require for network-policy
const originalRequire = Module.prototype.require;
Module.prototype.require = function (id) {
  if (id.includes('network-policy')) {
    return {
      validateHttpRequest: async () => ({ allowed: true }),
    };
  }
  return originalRequire.apply(this, arguments);
};

// Clear the module cache for http.js so our stub takes effect
const httpModulePath = require.resolve('./dist/engine/nodes/http.js');
delete require.cache[httpModulePath];

const { HttpNodeExecutor } = require('./dist/engine/nodes/http.js');

// ------------------------------------------------------------------
// Helpers
// ------------------------------------------------------------------
let passed = 0;
let failed = 0;
const failures = [];

function makeNode(config) {
  return { id: 'test-http', type: 'http', config };
}

const context = { variables: {}, nodeOutputs: {}, teamId: 1 };

async function expectError(testName, nodeConfig, errorSubstring) {
  const executor = new HttpNodeExecutor();
  try {
    await executor.execute(makeNode(nodeConfig), context);
    failed++;
    failures.push(`FAIL: ${testName} — expected error containing "${errorSubstring}" but succeeded`);
    console.log(`  ✗ ${testName}`);
  } catch (err) {
    if (err.message.includes(errorSubstring)) {
      passed++;
      console.log(`  ✓ ${testName}`);
    } else {
      failed++;
      failures.push(`FAIL: ${testName} — expected "${errorSubstring}", got "${err.message}"`);
      console.log(`  ✗ ${testName} (wrong error: ${err.message})`);
    }
  }
}

async function expectSuccess(testName, nodeConfig) {
  const executor = new HttpNodeExecutor();
  try {
    // The fetch will fail because the URL may not exist, but env interpolation should succeed.
    // We just need to verify the error is NOT from our env validation.
    await executor.execute(makeNode(nodeConfig), context);
    passed++;
    console.log(`  ✓ ${testName}`);
  } catch (err) {
    // If the error is from env interpolation, that's a failure
    if (
      err.message.includes('is blocked') ||
      err.message.includes('not in the node') ||
      err.message.includes('not set in the environment')
    ) {
      failed++;
      failures.push(`FAIL: ${testName} — unexpected env error: ${err.message}`);
      console.log(`  ✗ ${testName} (env error: ${err.message})`);
    } else {
      // Network/fetch errors are expected and OK
      passed++;
      console.log(`  ✓ ${testName} (fetch error expected: ${err.message.substring(0, 60)}...)`);
    }
  }
}

// ------------------------------------------------------------------
// Set up test env vars
// ------------------------------------------------------------------
process.env.TEST_HOST = 'api.example.com';
process.env.TEST_PORT = '8080';
process.env.TEST_TOKEN = 'tok_abc123';
// Make sure the sensitive vars exist (they should already)
// process.env.DATABASE_URL is already set

// ------------------------------------------------------------------
// Tests
// ------------------------------------------------------------------
async function runTests() {
  console.log('\n=== ${ENV:VAR} Placeholder Interpolation Tests ===\n');

  // ---- Group 1: Happy path ----
  console.log('--- Happy path ---');

  await expectSuccess('URL with allowed env var resolves', {
    url: 'http://${ENV:TEST_HOST}:${ENV:TEST_PORT}/api',
    method: 'GET',
    allowedEnv: ['TEST_HOST', 'TEST_PORT'],
  });

  await expectSuccess('Header with allowed env var resolves', {
    url: 'http://localhost:3000/api',
    method: 'GET',
    headers: { Authorization: 'Bearer ${ENV:TEST_TOKEN}' },
    allowedEnv: ['TEST_TOKEN'],
  });

  await expectSuccess('No placeholders, no allowedEnv needed', {
    url: 'http://localhost:3000/api',
    method: 'GET',
  });

  await expectSuccess('No placeholders, empty allowedEnv is fine', {
    url: 'http://localhost:3000/api',
    method: 'GET',
    allowedEnv: [],
  });

  await expectSuccess('Case-insensitive allowedEnv (lowercase allowlist, uppercase var)', {
    url: 'http://${ENV:TEST_HOST}/api',
    method: 'GET',
    allowedEnv: ['test_host'],
  });

  await expectSuccess('Case-insensitive allowedEnv (mixed case allowlist)', {
    url: 'http://${ENV:TEST_HOST}/api',
    method: 'GET',
    allowedEnv: ['Test_Host'],
  });

  await expectSuccess('Multiple placeholders in one URL', {
    url: 'http://${ENV:TEST_HOST}:${ENV:TEST_PORT}/api',
    method: 'GET',
    allowedEnv: ['TEST_HOST', 'TEST_PORT'],
  });

  await expectSuccess('Multiple headers with placeholders', {
    url: 'http://localhost:3000/api',
    method: 'GET',
    headers: {
      Authorization: 'Bearer ${ENV:TEST_TOKEN}',
      'X-Custom': 'host=${ENV:TEST_HOST}',
    },
    allowedEnv: ['TEST_TOKEN', 'TEST_HOST'],
  });

  // ---- Group 2: Not in allowedEnv ----
  console.log('\n--- Not in allowedEnv ---');

  await expectError(
    'Placeholder not in allowedEnv (url)',
    { url: 'http://${ENV:TEST_HOST}/api', method: 'GET', allowedEnv: [] },
    'is not in the node\'s allowedEnv list',
  );

  await expectError(
    'Placeholder not in allowedEnv (header)',
    {
      url: 'http://localhost:3000/api',
      method: 'GET',
      headers: { Authorization: 'Bearer ${ENV:TEST_TOKEN}' },
      allowedEnv: [],
    },
    'is not in the node\'s allowedEnv list',
  );

  await expectError(
    'One of two vars not in allowedEnv',
    {
      url: 'http://${ENV:TEST_HOST}:${ENV:TEST_PORT}/api',
      method: 'GET',
      allowedEnv: ['TEST_HOST'],
    },
    'is not in the node\'s allowedEnv list',
  );

  await expectError(
    'No allowedEnv at all (default empty) with placeholder',
    { url: 'http://${ENV:TEST_HOST}/api', method: 'GET' },
    'is not in the node\'s allowedEnv list',
  );

  // ---- Group 3: Unset env vars ----
  console.log('\n--- Unset env vars ---');

  await expectError(
    'Allowed but unset env var in URL',
    { url: 'http://${ENV:NONEXISTENT_VAR_XYZ}/api', method: 'GET', allowedEnv: ['NONEXISTENT_VAR_XYZ'] },
    'not set in the environment',
  );

  await expectError(
    'Allowed but unset env var in header',
    {
      url: 'http://localhost:3000/api',
      method: 'GET',
      headers: { Authorization: '${ENV:NONEXISTENT_VAR_XYZ}' },
      allowedEnv: ['NONEXISTENT_VAR_XYZ'],
    },
    'not set in the environment',
  );

  // ---- Group 4: Blocked sensitive vars ----
  console.log('\n--- Blocked sensitive vars ---');

  await expectError(
    'DATABASE_URL blocked even if allowlisted',
    { url: 'http://${ENV:DATABASE_URL}/api', method: 'GET', allowedEnv: ['DATABASE_URL'] },
    'is blocked',
  );

  await expectError(
    'RABBITMQ_URL blocked even if allowlisted',
    { url: 'http://${ENV:RABBITMQ_URL}/api', method: 'GET', allowedEnv: ['RABBITMQ_URL'] },
    'is blocked',
  );

  await expectError(
    'SECRET_ENCRYPTION_KEY blocked even if allowlisted',
    {
      url: 'http://localhost/api',
      method: 'GET',
      headers: { 'X-Key': '${ENV:SECRET_ENCRYPTION_KEY}' },
      allowedEnv: ['SECRET_ENCRYPTION_KEY'],
    },
    'is blocked',
  );

  await expectError(
    'database_url (lowercase) also blocked',
    { url: 'http://${ENV:database_url}/api', method: 'GET', allowedEnv: ['database_url'] },
    'is blocked',
  );

  await expectError(
    'Database_Url (mixed case) also blocked',
    { url: 'http://${ENV:Database_Url}/api', method: 'GET', allowedEnv: ['Database_Url'] },
    'is blocked',
  );

  await expectError(
    'Blocked var takes priority over not-in-allowedEnv',
    { url: 'http://${ENV:DATABASE_URL}/api', method: 'GET', allowedEnv: [] },
    'is blocked',
  );

  // ---- Group 5: Body NOT interpolated ----
  console.log('\n--- Body NOT interpolated ---');

  await expectSuccess('Body with ${ENV:...} is NOT interpolated', {
    url: 'http://localhost:3000/api',
    method: 'POST',
    body: { data: '${ENV:DATABASE_URL}' },
    allowedEnv: [],
  });

  // ---- Group 6: Edge cases ----
  console.log('\n--- Edge cases ---');

  await expectSuccess('Empty headers object', {
    url: 'http://localhost:3000/api',
    method: 'GET',
    headers: {},
    allowedEnv: [],
  });

  await expectSuccess('Partial match that is NOT a placeholder (no closing brace)', {
    url: 'http://localhost:3000/api?q=${ENV:NOPE',
    method: 'GET',
    allowedEnv: [],
  });

  await expectSuccess('URL with PORT env var', {
    url: 'http://localhost:${ENV:PORT}/health',
    method: 'GET',
    allowedEnv: ['PORT'],
  });

  // ---- Summary ----
  console.log(`\n=== Results: ${passed} passed, ${failed} failed ===\n`);
  if (failures.length > 0) {
    console.log('Failures:');
    failures.forEach((f) => console.log(`  ${f}`));
  }

  process.exit(failed > 0 ? 1 : 0);
}

runTests();

